class Solution:
    def validSubstringCount(self, word1: str, word2: str) -> int:
        def can_be_prefix(s):
            w2_count = {}
            for c in word2:
                w2_count[c] = w2_count.get(c, 0) + 1

            for c in s:
                if c in w2_count and w2_count[c] > 0:
                    w2_count[c] -= 1
                if all(count == 0 for count in w2_count.values()):
                    return True
            return False

        count = 0
        for i in range(len(word1)):
            for j in range(i + 1, len(word1) + 1):
                if can_be_prefix(word1[i:j]):
                    count += 1
        return count
